UPDATE review_merchant_reply
SET operator_id = #{operatorId},
    content = #{content},
    updated_at = CURRENT_TIMESTAMP
WHERE review_id = #{reviewId}
  AND merchant_id = #{merchantId}

UPDATE review
SET audit_status = 2,
    audit_remark = #{auditRemark},
    updated_at = CURRENT_TIMESTAMP
WHERE id = #{reviewId}
  AND region = #{region}
  AND audit_status = 1
  AND status = 1
  AND is_deleted = FALSE
  AND updated_at = #{baseReviewUpdatedAt}
